var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"너…… 여기까지 어떻게……?","JPN":"お前……どうやってここまで……？","ENG":"You...? But how...?","TWN":"你……怎麼會來這裡……？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그라운드 원으로 도주한 카운터 범죄자들을 체포하는 것도 우리 일이야.","JPN":"グラウンド・ワンに逃走したカウンターの犯罪者を逮捕するのも私たちの仕事なの。","ENG":"It's our job to arrest Criminal Counters who have fled to Ground One.","TWN":"逮補逃到G1的制裁者罪犯也是我們的職責所在。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그리고 여기, 코핀 컴퍼니는 사건 해결을 위해 협조한 적 있는 태스크포스고.","JPN":"それにここ、コフィンカンパニーは事件の解決のために協力したことがあるタスクフォースだし。","ENG":"And this TASKFORCE, Coffin Company, has cooperated with us in solving some cases.","TWN":"況且，這裡是曾經協助解決科芬公司事件的特遣勢力。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"신고가 들어오면 관심을 가질 수밖에 없지. 나나, 경위나.","JPN":"通報が入れば注意が向くのよ。私も、警部補も。","ENG":"When a report about this place comes in, the lieutenant and I can't help but pay attention.","TWN":"有人報警的話，不管是我或是姜素英員警，當然都必須來關心一下。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……코핀 컴퍼니. 그 용병들 회사였지.","JPN":"……コフィンカンパニー。あの傭兵たちの会社だったな。","ENG":"...Coffin Company. That's gotta be those mercs.","TWN":"……科芬公司，是那些傭兵的公司對吧？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아는? 승강기를 지키고 있었을 텐데?","JPN":"レヴィアは？　エレベーターを見張ってたはずだが？","ENG":"What about Levia? Isn't she supposed to be guarding the elevator?","TWN":"莉維亞呢？她不是該守著電梯嗎？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"지금 당신들 공범이 어디 있는지 나한테 물어 보는 거야?","JPN":"今あなたたちの共犯がどこにいるのか、私に聞くわけ？","ENG":"Are you asking me where your accomplice is?","TWN":"你現在是在問我，你們的共犯在哪裡嗎？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……레비아, 마지막까지 사고를 치는군.","JPN":"……レヴィア、最後までやらかしてくれるな。","ENG":"Levia, you had one job...","TWN":"……莉維亞，到最後還是在惹麻煩。"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"총에 맞았던 형사는 무사한가?","JPN":"銃に撃たれた刑事は無事か？","ENG":"How's the cop who got shot? Is she doing well?","TWN":"中槍的警察沒事吧？"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"목숨은 건졌어. 언제 죽을지 모르는 상태지만.","JPN":"命はあるわ。いつ死ぬかわからない状態だけど。","ENG":"She's alive. If barely.","TWN":"是撿回一條命，只是不知道什麼時候會死。"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"공무 수행 중인 경찰을 공격한 이상, 각오는 됐겠지?","JPN":"公務執行中の警察官を攻撃した以上、覚悟はできてるでしょうね？","ENG":"You know what's coming for you since you attacked an officer on duty, right?","TWN":"你們既然敢襲擊執勤的員警，應該就有做好心理準備吧？"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……변명은 하지 않겠다. 경찰을 해쳤으면 대가를 치러야지.","JPN":"……言い訳はしない。警察官を怪我させたんだ、償いはしないとな。","ENG":"...I have no excuse. I'll pay the price for my actions.","TWN":"……我不打算辯解，傷害警察就該付出代價。"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 우리는 이 일을 끝내야 해. 그 뒤에는 그쪽 마음대로 해라.","JPN":"だが俺たちはこの仕事を終わらせないといけないんだ。その後はそっちの勝手にしろ。","ENG":"But there's a job we need to finish. After that, I'll do as I'm told.","TWN":"但我們必須先解決這件事，決解完後就都聽你的。"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"누가 당신 말대로 할 줄 알아?! 명령하지 마!","JPN":"あなたの言うとおりになんかすると思う？！　命令しないで！","ENG":"Who're you to tell me what to do, huh?! Don't order me around!","TWN":"你以為我會聽你的嗎？！少命令我！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"으윽……?!","JPN":"ううっ……！？","ENG":"Ugh...?!","TWN":"唔唔……？！"},"stage":{"bg":"TERRA","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잡았다, 이 범죄자!","JPN":"捕まえた！　この犯罪者！","ENG":"You're mine now, criminal!","TWN":"束手就擒吧！"},"stage":{"bg":"TERRA","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};